          workspaceId,
          deploymentId: created.deployment.id,
          eventType: 'deployment_enqueued',
          payload: {
            mode: env.WORKSPACE_DEPLOYS_QUEUE ? 'queue' : 'inline',
            reused: created.reused,
          },
        });

        if (shouldRecoverQueued && !hasRecoveredReenqueue) {
