    await appendWorkspaceDeploymentEvent(env.DB, {
      workspaceId,
      deploymentId,
      eventType: 'deployment_toolchain_bootstrap_started',
      payload: {
        manager: toolchain.manager,
        version: toolchain.version,
      },
    });
